    bool largeAllowedWithMonitoring;
    bool guardSucceeded;
    bool allocationBlockedAtLimit;
    bool runtimeAllowedAfterRelease;
};

/**
 * Function: Demonstrate StackMonitor::canAllocate behaviour across modes.
 *
 * @param largeSize Value used for runtime canAllocate after release
 * @return StackAllocationSnapshot Snapshot of allocation checks before/after guard
 */
inline StackAllocationSnapshot test_stack_monitor_capacity(std::size_t largeSize) {
    // 1. Disable monitoring
    reaction::memory::StackMonitor::setMonitoring(false);

    // 2. Initialize stack monitor
    reaction::memory::StackMonitor::initialize();

    // 3. Check allocation without monitoring
    const size_t smallSize = reaction::memory::SBOConfig::ALWAYS_SBO_SIZE;
    const size_t largeStaticSize = reaction::memory::SBOConfig::CONDITIONAL_SBO_SIZE;

    bool smallAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate(smallSize);
    bool largeAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate(largeStaticSize);
    bool runtimeAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate(largeSize);

    // 4. Enable monitoring
    reaction::memory::StackMonitor::setMonitoring(true);

    // 5. Initialize stack monitor again
    reaction::memory::StackMonitor::initialize();

    // 6. Check large allocation with monitoring
    bool largeAllowedWithMonitoring = reaction::memory::StackMonitor::canAllocate(largeStaticSize);

    // 7. Create StackGuard in scope block
    reaction::memory::StackGuard<reaction::memory::SBOConfig::MAX_SBO_STACK_USAGE> guard;

    // 8. Check if guard succeeded
    bool guardSucceeded = guard.allocated;

    // 9. Check if allocation blocked at limit
    bool allocationBlockedAtLimit = !reaction::memory::StackMonitor::canAllocate(
        reaction::memory::SBOConfig::MAX_SBO_STACK_USAGE);

    // 10. Exit guard scope (automatic when function returns)

    // 11. Check runtime allocation after release
    bool runtimeAllowedAfterRelease = reaction::memory::StackMonitor::canAllocate(largeSize);

    // 12. Return stack allocation snapshot
    return StackAllocationSnapshot{
        smallAllowedWithoutMonitoring,
        largeAllowedWithoutMonitoring,
        runtimeAllowedWithoutMonitoring,
        largeAllowedWithMonitoring,
        guardSucceeded,
        allocationBlockedAtLimit,
        runtimeAllowedAfterRelease
    };
}

}  // namespace test_reaction

